### Core Watch Logic

```rust
use notify::{Watcher, RecommendedWatcher, RecursiveMode, Event, EventKind};
use std::sync::mpsc;
use std::time::{Duration, Instant};

pub fn watch_and_correct(config: &Config, path: &Path) -> Result<(), Error> {
    test_log!("INFO", "Starting watch mode for: {:?}", path);

    let (tx, rx) = mpsc::channel();
    let mut watcher = RecommendedWatcher::new(
        move |res: Result<Event, _>| {
            if let Ok(event) = res {
                let _ = tx.send(event);
            }
        },
        notify::Config::default()
    )?;

    watcher.watch(path, RecursiveMode::NonRecursive)?;
    test_log!("DEBUG", "Watcher initialized, debounce={}ms", config.debounce_ms);

    eprintln!("Watching {} for changes (Ctrl+C to stop)...", path.display());

    let mut last_event = Instant::now();
    let debounce = Duration::from_millis(config.debounce_ms);

    loop {
        match rx.recv_timeout(Duration::from_millis(100)) {
            Ok(event) => {
                if matches!(event.kind, EventKind::Modify(_)) {
                    let now = Instant::now();
                    if now.duration_since(last_event) >= debounce {
                        test_log!("INFO", "File modified, running correction...");
                        last_event = now;

                        match process_file(config, path) {
                            Ok(stats) => {
                                if stats.revisions_applied > 0 {
                                    eprintln!("✓ Applied {} revision(s)", stats.revisions_applied);
                                } else {
                                    eprintln!("✓ No changes needed");
                                }
                            }
                            Err(e) => {
                                eprintln!("✗ Error: {}", e);
                            }
                        }
                    }
                }
            }
            Err(mpsc::RecvTimeoutError::Timeout) => continue,
            Err(mpsc::RecvTimeoutError::Disconnected) => break,
        }
    }

    Ok(())
}
```

