## Implementation

### Quick Scan Function

```rust
/// Characters that indicate box-drawing content
const BOX_CHARS: &[char] = &[
    // ASCII box drawing
    '+', '|', '-',
    // Unicode box drawing
    '─', '━', '│', '┃', '┌', '┐', '└', '┘',
    '├', '┤', '┬', '┴', '┼',
    '╔', '╗', '╚', '╝', '║', '═',
    '╭', '╮', '╯', '╰',
];

/// Quickly scan input to determine if it likely contains diagrams
pub fn quick_scan_for_diagrams(input: &str) -> QuickScanResult {
    test_log!("INFO", "Starting quick scan for diagram detection");

    let start = std::time::Instant::now();
    let mut lines_scanned = 0;
    let mut lines_with_box_chars = 0;

    for line in input.lines().take(QUICK_SCAN_LIMIT) {
        lines_scanned += 1;
        if line.chars().any(|c| BOX_CHARS.contains(&c)) {
            lines_with_box_chars += 1;
        }
    }

    let elapsed = start.elapsed();
    let ratio = if lines_scanned > 0 {
        lines_with_box_chars as f64 / lines_scanned as f64
    } else {
        0.0
    };

    let likely_has_diagrams = ratio >= QUICK_SCAN_THRESHOLD;

    test_log!("DEBUG", "Quick scan: {}/{} lines have box chars ({:.1}%), threshold={:.1}%",
        lines_with_box_chars, lines_scanned, ratio * 100.0, QUICK_SCAN_THRESHOLD * 100.0);
    test_log!("DEBUG", "Quick scan completed in {:?}", elapsed);

    QuickScanResult {
        lines_scanned,
        lines_with_box_chars,
        ratio,
        likely_has_diagrams,
        scan_time: elapsed,
    }
}

#[derive(Debug)]
pub struct QuickScanResult {
    pub lines_scanned: usize,
    pub lines_with_box_chars: usize,
    pub ratio: f64,
    pub likely_has_diagrams: bool,
    pub scan_time: std::time::Duration,
}
```

### Integration with Main Processing

```rust
pub fn process_input(config: &Config, input: &str) -> Result<String, Error> {
    // Skip quick scan if --all flag is set (process everything)
    if !config.all {
        let scan = quick_scan_for_diagrams(input);

        if !scan.likely_has_diagrams {
            test_log!("INFO", "Quick scan: no diagrams detected, passing through unchanged");

            if config.verbose {
                eprintln!(
                    "Quick scan: no diagrams detected ({:.1}% box chars < {:.1}% threshold)",
                    scan.ratio * 100.0,
                    QUICK_SCAN_THRESHOLD * 100.0
                );
                eprintln!("Passing through unchanged (use --all to force processing)");
            }

            // Return input unchanged
            return Ok(input.to_string());
        }

        test_log!("DEBUG", "Quick scan: diagrams likely present, proceeding with full processing");
    }

    // Full processing
    let (output, _stats) = process_with_stats(config, input);
    Ok(output)
}
